pub fn new_scheduled(transaction: T) -> Self {
    let sender = transaction.sender();
    let sender_bytes = sender.as_slice();
    let mut sender_u64_bytes = [0u8; 8];
    for i in 0..std::cmp::min(8, sender_bytes.len()) {
        sender_u64_bytes[i] = sender_bytes[i];
    }
    let sender_u64 = u64::from_be_bytes(sender_u64_bytes);
